#!/usr/bin/env python3
import ast
import sys

def find_property_def(tree, name):
    """Find property or cache_readonly decorated method definitions"""
    for node in ast.walk(tree):
        if isinstance(node, ast.FunctionDef):
            # Check for @cache_readonly decorator
            for decorator in node.decorator_list:
                if (isinstance(decorator, ast.Name) and decorator.id in ('cache_readonly', 'property')) or \
                   (isinstance(decorator, ast.Attribute) and decorator.attr in ('cache_readonly', 'property')):
                    if node.name == name:
                        return True
    return False

def find_usages(tree, attr_name):
    """Find usages of self._index_engine or similar patterns"""
    count = 0
    for node in ast.walk(tree):
        if isinstance(node, ast.Attribute):
            if node.attr == attr_name:
                count += 1
    return count

files_info = {
    'pandas/core/indexes/base.py': 'Index (base class)',
    'pandas/core/indexes/multi.py': 'MultiIndex',
    'pandas/core/indexes/interval.py': 'IntervalIndex',
    'pandas/core/indexes/category.py': 'CategoricalIndex'
}

print("\n" + "="*70)
print("VERIFICATION: _engine renamed to _index_engine")
print("="*70 + "\n")

all_good = True
for filepath, classname in files_info.items():
    try:
        with open(filepath, 'r') as f:
            code = f.read()
        tree = ast.parse(code)

        has_new_def = find_property_def(tree, '_index_engine')
        has_old_def = find_property_def(tree, '_engine')
        new_usages = find_usages(tree, '_index_engine')

        print(f"✓ {classname:20} ({filepath})")
        print(f"  - _index_engine property: {'DEFINED' if has_new_def else 'not defined'}")
        print(f"  - _engine property (old):  {'FOUND (ERROR!)' if has_old_def else 'removed'}")
        print(f"  - Total usages of _index_engine: {new_usages}")

        if has_old_def:
            all_good = False
        print()

    except Exception as e:
        print(f"✗ {classname}: ERROR - {e}\n")
        all_good = False

print("="*70)
if all_good:
    print("SUCCESS: All renaming completed successfully!")
else:
    print("FAILURE: Some issues found!")
    sys.exit(1)
print("="*70 + "\n")
